mapper.select:
select id, org_post_id, module_id, module_visible, nav_visible, create_by, create_time, update_by, update_time, note
from sys_org_post_module_auth
where org_post_id = #{orgPostId}
  and module_id = #{moduleId}
limit 1

select id, org_post_id, module_id, field_id, permission_level, create_by, create_time, update_by, update_time, note
from sys_org_post_field_auth
where org_post_id = #{orgPostId}
  and module_id = #{moduleId}
order by id asc

select id, org_post_id, module_id, button_id, permission_level, create_by, create_time, update_by, update_time, note
from sys_org_post_button_auth
where org_post_id = #{orgPostId}
  and module_id = #{moduleId}
order by id asc

select id, org_post_id, module_id, button_id, permission_level, create_by, create_time, update_by, update_time, note
from sys_org_post_button_auth
where org_post_id = #{orgPostId}
  and button_id = #{buttonId}
limit 1

mapper.delete:
